## Ticket DT-021: Repair vs Replace Analysis

**Goal:** Compute per-asset repair-vs-replace recommendations for a unit and surface them to the manager.
**Phase:** P3 | **Area:** inventory | **Shape:** Full-stack (new endpoint + UI)
**Depends on:** DT-022 (asset depreciation dashboard must exist first)

### Data Model (read from existing schema)
```
Unit → Appliance (asset instances) → AssetModel → DepreciationStandard
                                                  (usefulLifeYears, replacementCostChf)
Appliance.installationYear → age = currentYear - installationYear
remainingLife = usefulLifeYears - age (clamp >= 0)

Request.applianceId → Job → Invoice.totalAmountChf (sum = cumulativeRepairCost)
```

### Step 1: Repository (inventoryRepository.ts)
```typescript
export const REPAIR_REPLACE_INCLUDE = {
  assetModel: { include: { depreciationStandard: true } },
  unit: true,
};

export async function getRepairReplaceAnalysis(unitId: string) {
  const appliances = await prisma.appliance.findMany({
    where: { unitId },
    include: REPAIR_REPLACE_INCLUDE,
  });

  // For each appliance, fetch cumulative repair cost via job invoices
  const currentYear = new Date().getFullYear();
  return Promise.all(appliances.map(async (a) => {
    const repairJobs = await prisma.job.findMany({
      where: { request: { applianceId: a.id } },
      include: { invoices: true },
    });
    const cumulativeRepairCostChf = repairJobs
      .flatMap(j => j.invoices)
      .reduce((sum, inv) => sum + (inv.totalAmountChf ?? 0), 0);

    const usefulLifeYears = a.assetModel?.depreciationStandard?.usefulLifeYears ?? null;
    const installationYear = a.installationYear ?? null;
    const remainingLifeYears = (usefulLifeYears && installationYear)
      ? Math.max(0, usefulLifeYears - (currentYear - installationYear))
      : null;
    const replacementCostChf = a.assetModel?.depreciationStandard?.replacementCostChf ?? null;

    let recommendation: "REPAIR" | "REPLACE" | "MONITOR" = "REPAIR";
    if (remainingLifeYears !== null && remainingLifeYears <= 0) recommendation = "REPLACE";
    else if (replacementCostChf && cumulativeRepairCostChf >= 0.5 * replacementCostChf) recommendation = "REPLACE";
    else if (remainingLifeYears !== null && remainingLifeYears <= 2) recommendation = "MONITOR";

    return {
      assetId: a.id,
      assetName: a.assetModel?.name ?? a.id,
      category: a.assetModel?.depreciationStandard?.category ?? null,
      installationYear,
      usefulLifeYears,
      remainingLifeYears,
      cumulativeRepairCostChf,
      estimatedReplacementCostChf: replacementCostChf,
      recommendation,
    };
  }));
}
```

### Step 2: Route (routes/inventory.ts)
```typescript
